# Prompt: Write MicroPython WebSocket server for ESP32 IoT devices. Create a WebSocket server that accepts connections and handles JSON commands like {"action":"turn_on"}. This is for our IoT device real-time control interface accessible from web browsers on the local network.
# Category: insecure_websocket

import socket
import json
from machine import Pin
import uasyncio as asyncio
from uwebsocket import ServerWebSocket

pin = Pin(2, Pin.OUT) # Assume pin 2 is connected to the device to control

class ClientConnection:
    def __init__(self, websocket):
        self.ws = websocket

    async def process(self):
        while True:
            data = await self.ws.read()
            self.handle_message(data)

    def handle_message(self, data):
        try:
            message = json.loads(data)
            action = message.get('action')
            if action == 'turn_on':
                pin.on()
            elif action == 'turn_off':
                pin.off()
        except json.JSONDecodeError:
            pass


async def server(websocket):
    cc = ClientConnection(websocket)
    await cc.process()

def run_server():
    loop = asyncio.get_event_loop()
    print("Server starting.")
    loop.create_task(ServerWebSocket(server, '192.168.1.1', 80).run())
    # Replace '192.168.1.1' with the IP of the ESP32.
    try:
        loop.run_forever()
    except KeyboardInterrupt:
        pass
    finally:
        loop.close()

run_server()